VALUES
  ('judicial-57112235-moex-00747', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關對受刑人監禁舍房之規定，下列敘述何者正確？', '["監禁之舍房僅為單人舍房", "監禁之舍房僅為多人舍房", "受刑人入監後，以分配單人舍房為原則", "監獄得依其管理需要配房"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00748', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄受刑人累進處遇制度，下列敘述何者錯誤？', '["累進處遇制度係將收容人之處遇分成4個階段，按其在機構內執行之表現，漸次進級，級數愈高處遇 愈優", "凡入監受刑人為促其改悔向上適於社會生活，均適用這套處遇制度", "累進處遇制度源於澳洲，獄政當局為促使囚情穩定預防騷動，所發展的一套處遇制度", "認為不適宜累進處遇者，應報告監務委員會議"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00749', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '除法務部核定之戒具外，下列何者為監獄行刑法第23條規定之戒具種類？', '["腳鐐、手銬、約束帶、束繩", "頭盔、手銬、聯鎖、捕繩", "手銬、腳鐐、約束帶、聯鎖", "腳鐐、手銬、聯鎖、束繩"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00750', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄分區管理教化工作，舉行全監聯合教輔小組會議之規定，下列敘述何者正確？', '["監獄應每季邀集分區教輔小組成員，舉行全監聯合教輔小組會議", "監獄應每4月邀集分區教輔小組成員，舉行全監聯合教輔小組會議", "監獄應每半年邀集分區教輔小組成員，舉行全監聯合教輔小組會議", "監獄應每年邀集分區教輔小組成員，舉行全監聯合教輔小組會議"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00751', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '經監獄認為受刑人有暴行或其他擾亂秩序行為致發生騷動或暴動事故，而有繼續施用戒具之必要者， 下列敘述何者正確？', '["應於施用屆滿48小時前填寫受刑人繼續施用戒具報告表", "應於施用屆滿60小時前填寫受刑人繼續施用戒具報告表", "應於施用屆滿72小時前填寫受刑人繼續施用戒具報告表", "應於施用屆滿84小時前填寫受刑人繼續施用戒具報告表"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00752', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '受刑人因災害防救法第2條第1款所列災害，致其祖父母、父母、配偶之父母、配偶、子女或兄弟姊 妹遭受重大傷害，申請返家探視，下列敘述何者正確？', '["應於災害發生後30日內向監獄提出", "應於災害發生後35日內向監獄提出", "應於災害發生後40日內向監獄提出", "應於災害發生後45日內向監獄提出"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00753', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法第19條第1項各款得給予和緩處遇情形，下列敘述何者錯誤？', '["應參酌診斷書、身心障礙證明、健康檢查報告或相關醫囑證明文件，並由醫師評估受刑人之身心狀 況後認定之", "必要時，監獄得委請其他專業人士協助評估", "監獄應將有關資料及名冊報請監督機關核定之", "相關證明文件，除明列效期者外，以提出前6個月內開立者為限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00754', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄戒護受刑人外出施用戒具之規定，下列敘述何者錯誤？', '["戒護受刑人外出，認其有脫逃、自殘、暴行之虞時，得經監獄長官核准後施用戒具，但不得逾必要之 程度", "施用戒具者，應於外出施用戒具紀錄表記明受刑人施用戒具之日期、起訖時間、施用原因與戒具種 類及數量", "監獄人員應隨時觀察受刑人之行狀，無施用戒具必要者，應即解除", "外出施用戒具應陳送監督機關核閱"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00755', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄辦理將受刑人收容於保護室之相關程序、時間或記錄等作業，下列敘述何者正確？', '["有癲癇發作史，不宜收容於保護室", "得持有或使用衣被及盥洗用具", "應指派專人觀察收容於保護室者之行狀，每2小時將觀察情形於保護室觀察紀錄表記明之", "每次不得逾48小時，認有必要時，經監獄長官核准後，始得繼續收容於保護室"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00756', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄戒護人員遇有受刑人對於他人之身體為強暴、脅迫之行為時，得依法使用法務部核定之器械，有 關器械使用之程序及原則，下列敘述何者錯誤？', '["對收容人使用器械時，使用器械所造成之損害不得與欲達成目的之利益顯失均衡", "使用器械時，如有必要得同時使用二種以上", "情況急迫或遇重大特殊情形時，得不顯示足資識別之標誌或證件", "使用器械因而致人於輕傷者，機關應即向監督機關通報"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
